}

namespace ShipmentTracker.Models;

using ShipmentTracker.Data;

public record ShipmentStatusUpdate(ShipmentStatus Status);
public record CreateShipmentRequest(string TrackingNumber, string Origin, string Destination, DateTime EstimatedDelivery, string CustomerEmail);

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentService(HttpClient http)
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        var result = await http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments");
        return result ?? [];
    }

    public async Task<ShipmentDto?> TrackShipmentAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"/api/shipments/track/{trackingNumber}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<bool> UpdateStatusAsync(int id, ShipmentStatus status)
    {
        var response = await http.PutAsJsonAsync($"/api/shipments/{id}/status", new { Status = status });
        return response.IsSuccessStatusCode;
    }

    public async Task<bool> CreateShipmentAsync(ShipmentDto shipment)
    {
        var response = await http.PostAsJsonAsync("/api/shipments", new
        {
            shipment.TrackingNumber,
            shipment.Origin,
            shipment.Destination,
            shipment.EstimatedDelivery,
            shipment.CustomerEmail
        });
        return response.IsSuccessStatusCode;
    }
}

using Microsoft.AspNetCore.Identity;

namespace ShipmentTracker.Data;

public static class SeedData
{
    public static async Task InitializeAsync(IServiceProvider serviceProvider)
    {
        var roleManager = serviceProvider.GetRequiredService<RoleManager<IdentityRole>>();
        var userManager = serviceProvider.GetRequiredService<UserManager<ApplicationUser>>();
        var db = serviceProvider.GetRequiredService<ApplicationDbContext>();

        // Create roles
        string[] roles = ["Dispatcher", "Customer"];
        foreach (var role in roles)
        {
            if (!await roleManager.RoleExistsAsync(role))
            {
                await roleManager.CreateAsync(new IdentityRole(role));
            }
        }

        // Create dispatcher user
        var dispatcherEmail = "dispatcher@shiptrack.com";
        if (await userManager.FindByEmailAsync(dispatcherEmail) is null)
        {
            var dispatcher = new ApplicationUser
            {
                UserName = dispatcherEmail,
                Email = dispatcherEmail,
                EmailConfirmed = true
            };
            await userManager.CreateAsync(dispatcher, "Pass123!");
            await userManager.AddToRoleAsync(dispatcher, "Dispatcher");
        }

        // Create customer user
        var customerEmail = "customer@shiptrack.com";
        if (await userManager.FindByEmailAsync(customerEmail) is null)
        {
            var customer = new ApplicationUser
            {
                UserName = customerEmail,
                Email = customerEmail,
                EmailConfirmed = true
            };
            await userManager.CreateAsync(customer, "Pass123!");
            await userManager.AddToRoleAsync(customer, "Customer");
        }

        // Seed shipments
        if (!db.Shipments.Any())
        {
            db.Shipments.AddRange(
                new Shipment
                {
                    TrackingNumber = "SHP-001",
                    Origin = "New York, NY",
                    Destination = "Los Angeles, CA",
                    Status = ShipmentStatus.InTransit,
                    ShippedDate = DateTime.UtcNow.AddDays(-3),
                    EstimatedDelivery = DateTime.UtcNow.AddDays(2),
                    CustomerEmail = customerEmail
                },
                new Shipment
                {
                    TrackingNumber = "SHP-002",
                    Origin = "Chicago, IL",
                    Destination = "Houston, TX",
                    Status = ShipmentStatus.Pending,
                    ShippedDate = DateTime.UtcNow.AddDays(-1),
                    EstimatedDelivery = DateTime.UtcNow.AddDays(4),
                    CustomerEmail = customerEmail
                },
                new Shipment
                {
                    TrackingNumber = "SHP-003",
                    Origin = "Seattle, WA",
                    Destination = "Miami, FL",
                    Status = ShipmentStatus.OutForDelivery,
                    ShippedDate = DateTime.UtcNow.AddDays(-5),
                    EstimatedDelivery = DateTime.UtcNow,
                    CustomerEmail = customerEmail
                },
                new Shipment
                {
                    TrackingNumber = "SHP-004",
                    Origin = "Boston, MA",
                    Destination = "Denver, CO",
                    Status = ShipmentStatus.Delivered,
                    ShippedDate = DateTime.UtcNow.AddDays(-7),
                    EstimatedDelivery = DateTime.UtcNow.AddDays(-2),
                    CustomerEmail = customerEmail
                }
            );
            await db.SaveChangesAsync();
        }
    }
}

