@page "/shipments"
@attribute [Authorize(Roles = "Dispatcher")]
@using Microsoft.AspNetCore.Authorization

<PageTitle>Shipments Dashboard</PageTitle>

<h1>Shipments Dashboard</h1>

<h3>Create New Shipment</h3>
<div class="card mb-4 p-3">
    <div class="row g-2">
        <div class="col-md-2">
            <input @bind="newShipment.TrackingNumber" class="form-control" placeholder="Tracking #" />
        </div>
        <div class="col-md-2">
            <input @bind="newShipment.Origin" class="form-control" placeholder="Origin" />
        </div>
        <div class="col-md-2">
            <input @bind="newShipment.Destination" class="form-control" placeholder="Destination" />
        </div>
        <div class="col-md-2">
            <input @bind="newShipment.EstimatedDelivery" type="date" class="form-control" />
        </div>
        <div class="col-md-2">
            <input @bind="newShipment.CustomerEmail" class="form-control" placeholder="Customer Email" />
        </div>
        <div class="col-md-2">
            <button class="btn btn-primary w-100" @onclick="CreateShipment">Create</button>
        </div>
    </div>
    @if (!string.IsNullOrEmpty(createMessage))
    {
        <div class="alert alert-info mt-2">@createMessage</div>
    }
</div>

<h3>All Shipments</h3>
@if (shipments is null)
{
    <p>Loading...</p>
}
else if (shipments.Count == 0)
{
    <p>No shipments found.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped Date</th>
                <th>Est. Delivery</th>
                <th>Customer</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in shipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge bg-@GetStatusColor(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.ShippedDate.ToString("yyyy-MM-dd")</td>
                    <td>@shipment.EstimatedDelivery.ToString("yyyy-MM-dd")</td>
                    <td>@shipment.CustomerEmail</td>
                    <td>
                        <select class="form-select form-select-sm" value="@((int)shipment.Status)"
                            @onchange="(e) => UpdateStatus(shipment.Id, e)">
                            @foreach (ShipmentStatus status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@((int)status)">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Inject] private ShipmentService ShipmentService { get; set; } = default!;

    private List<ShipmentDto>? shipments;
    private ShipmentDto newShipment = new() { EstimatedDelivery = DateTime.Now.AddDays(5) };
    private string? createMessage;

