using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using System.Security.Claims;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Pages;
using ShipmentTracker.Components;
using ShipmentTracker.Components.Account;
using ShipmentTracker.Data;
using ShipmentTracker.Models;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveWebAssemblyComponents()
    .AddAuthenticationStateSerialization();

builder.Services.AddCascadingAuthenticationState();
builder.Services.AddScoped<IdentityRedirectManager>();

builder.Services.AddAuthentication(options =>
    {
        options.DefaultScheme = IdentityConstants.ApplicationScheme;
        options.DefaultSignInScheme = IdentityConstants.ExternalScheme;
    })
    .AddIdentityCookies();

builder.Services.AddAuthorizationBuilder()
    .AddPolicy("DispatcherPolicy", policy => policy.RequireRole("Dispatcher"));

var connectionString = builder.Configuration.GetConnectionString("DefaultConnection") ?? throw new InvalidOperationException("Connection string 'DefaultConnection' not found.");
builder.Services.AddDbContext<ApplicationDbContext>(options =>
    options.UseSqlite(connectionString));
builder.Services.AddDatabaseDeveloperPageExceptionFilter();

builder.Services.AddIdentityCore<ApplicationUser>(options =>
    {
        options.SignIn.RequireConfirmedAccount = true;
        options.Stores.SchemaVersion = IdentitySchemaVersions.Version3;
    })
    .AddRoles<IdentityRole>()
    .AddEntityFrameworkStores<ApplicationDbContext>()
    .AddSignInManager()
    .AddDefaultTokenProviders();

builder.Services.AddSingleton<IEmailSender<ApplicationUser>, IdentityNoOpEmailSender>();

builder.Services.AddScoped(sp => new HttpClient { BaseAddress = new Uri("https://localhost") });
builder.Services.AddScoped<ShipmentTracker.Client.Services.ShipmentService>();

var app = builder.Build();

// Seed data
using (var scope = app.Services.CreateScope())
{
    var services = scope.ServiceProvider;
    var db = services.GetRequiredService<ApplicationDbContext>();
    db.Database.Migrate();
    await SeedData.InitializeAsync(services);
}

// Configure the HTTP request pipeline.
if (app.Environment.IsDevelopment())
{
    app.UseWebAssemblyDebugging();
    app.UseMigrationsEndPoint();
}
else
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
    // The default HSTS value is 30 days. You may want to change this for production scenarios, see https://aka.ms/aspnetcore-hsts.
    app.UseHsts();
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
app.UseHttpsRedirection();

app.UseAntiforgery();

app.MapStaticAssets();
app.MapRazorComponents<App>()
    .AddInteractiveWebAssemblyRenderMode()
    .AddAdditionalAssemblies(typeof(ShipmentTracker.Client._Imports).Assembly);

// Add additional endpoints required by the Identity /Account Razor components.
app.MapAdditionalIdentityEndpoints();

// API endpoints
var shipments = app.MapGroup("/api/shipments").RequireAuthorization();

shipments.MapGet("/", async (ApplicationDbContext db) =>
{
    var items = await db.Shipments.OrderByDescending(s => s.ShippedDate).ToListAsync();
    return items.Select(s => new ShipmentDto
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (ShipmentTracker.Client.Models.ShipmentStatus)(int)s.Status,
        ShippedDate = s.ShippedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        CustomerEmail = s.CustomerEmail
    });
}).RequireAuthorization("DispatcherPolicy");

shipments.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db, HttpContext http) =>
{
    var userEmail = http.User.FindFirstValue(ClaimTypes.Email);
    var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber && s.CustomerEmail == userEmail);
    if (shipment is null) return Results.NotFound();
    return Results.Ok(new ShipmentDto
    {
        Id = shipment.Id,
        TrackingNumber = shipment.TrackingNumber,
        Origin = shipment.Origin,
        Destination = shipment.Destination,
        Status = (ShipmentTracker.Client.Models.ShipmentStatus)(int)shipment.Status,
        ShippedDate = shipment.ShippedDate,
        EstimatedDelivery = shipment.EstimatedDelivery,
        CustomerEmail = shipment.CustomerEmail
    });
});

shipments.MapPut("/{id}/status", async (int id, ShipmentStatusUpdate update, ApplicationDbContext db) =>
{
    var shipment = await db.Shipments.FindAsync(id);
    if (shipment is null) return Results.NotFound();
    shipment.Status = (ShipmentTracker.Data.ShipmentStatus)(int)update.Status;
    await db.SaveChangesAsync();
    return Results.Ok();
}).RequireAuthorization("DispatcherPolicy");

shipments.MapPost("/", async (CreateShipmentRequest request, ApplicationDbContext db) =>
{
    var shipment = new Shipment
    {
        TrackingNumber = request.TrackingNumber,
        Origin = request.Origin,
        Destination = request.Destination,
        Status = ShipmentTracker.Data.ShipmentStatus.Pending,
        ShippedDate = DateTime.UtcNow,
        EstimatedDelivery = request.EstimatedDelivery,
        CustomerEmail = request.CustomerEmail
    };
    db.Shipments.Add(shipment);
    await db.SaveChangesAsync();
    return Results.Created($"/api/shipments/{shipment.Id}", new ShipmentDto
    {
        Id = shipment.Id,
        TrackingNumber = shipment.TrackingNumber,
        Origin = shipment.Origin,
        Destination = shipment.Destination,
        Status = (ShipmentTracker.Client.Models.ShipmentStatus)(int)shipment.Status,
        ShippedDate = shipment.ShippedDate,
        EstimatedDelivery = shipment.EstimatedDelivery,
        CustomerEmail = shipment.CustomerEmail
    });
}).RequireAuthorization("DispatcherPolicy");

app.Run();

